const question = $.input.question;
// Extract key terms for Drive search — remove common stop words
const stopWords = ['what','is','the','a','an','how','does','do','can','where','when','which','who','why','are','was','were','been','being','have','has','had','will','would','should','could','may','might','shall','about','into','through','during','before','after','above','below','from','with','this','that','these','those','for','and','but','or'];
const keywords = question.split(/\s+/).filter(w => w.length > 2 && !stopWords.includes(w.toLowerCase())).slice(0, 5).join(' ');

let q = "trashed=false and mimeType != 'application/vnd.google-apps.folder'";
if (keywords) q += " and fullText contains '" + keywords.replace(/'/g, '') + "'";
if ($.input.folderId) q += " and '" + $.input.folderId + "' in parents";

return { searchQuery: q, keywords };

const files = ($.steps.searchFiles.response.files || []).slice(0, 5);
const exportable = files.map(f => ({
  id: f.id,
  name: f.name,
  mimeType: f.mimeType,
  modifiedTime: f.modifiedTime,
  isGoogleDoc: (f.mimeType || '').startsWith('application/vnd.google-apps.')
}));

return { files: exportable, fileCount: exportable.length };

const files = $.steps.selectFiles.output.files || [];
const iterations = $.steps.fetchContent.response.iterations || [];

let docsText = '';
files.forEach((f, i) => {
  const iter = iterations[i] || {};
  const exportResp = iter.exportFile || {};
  // The export endpoint returns raw text, not JSON
  let content = '';
  if (exportResp.response) {
    content = typeof exportResp.response === 'string' ? exportResp.response : JSON.stringify(exportResp.response);
  }
  content = content.slice(0, 4000);

  docsText += '--- DOCUMENT ' + (i+1) + ' ---\n';
  docsText += 'Title: ' + f.name + '\n';
  docsText += 'Modified: ' + (f.modifiedTime || 'Unknown') + '\n';
  docsText += 'Content:\n' + (content || '(No content extracted)') + '\n\n';
});

return { docsText, docCount: files.length };

const prompt = `You are a helpful company knowledge assistant. Answer the employee's question ONLY based on the company documents provided below. If the documents don't contain enough information to answer, say so clearly.

EMPLOYEE QUESTION: ${$.input.question}

COMPANY DOCUMENTS (${$.steps.compileDocuments.output.docCount} found):
${$.steps.compileDocuments.output.docsText}

INSTRUCTIONS:
- Answer based strictly on the document content
- Reference which document(s) you used by number, e.g. [Doc 1]
- If multiple documents provide relevant info, synthesize them
- If the documents don't address the question, say "I couldn't find information about this in the available documents" and suggest what to search for
- Be concise but thorough
- Use Slack mrkdwn formatting: *bold* (NOT **bold**), _italic_, > for quotes. No markdown tables. No # headings.

Return ONLY valid JSON:
{
  "answer": "<answer grounded in document content, using Slack mrkdwn>",
  "documentsUsed": [<document numbers used>],
  "confidence": "high|medium|low",
  "suggestedFollowUp": "<optional follow-up question>"
}`;

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, documentsUsed: [], confidence: 'medium', suggestedFollowUp: '' }; }

const ai = $.steps.parseAI.output || {};
const question = $.input.question;
const files = $.steps.selectFiles.output.files || [];
const docCount = $.steps.compileDocuments.output.docCount;

const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];

blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Company Knowledge Answer' } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answerText } });
blocks.push({ type: 'divider' });

// Show which documents were referenced
const usedDocs = (ai.documentsUsed || []);
if (usedDocs.length > 0 && files.length > 0) {
  let docList = '*Documents Referenced:*\n';
  usedDocs.forEach(num => {
    const f = files[num - 1];
    if (f) docList += ':page_facing_up: ' + f.name + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: docList } });
}

if (ai.suggestedFollowUp) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':bulb: *Try asking:* ' + ai.suggestedFollowUp } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceEmoji + ' Confidence: *' + (ai.confidence || 'medium') + '* | Documents searched: *' + docCount + '* | Documents cited: *' + usedDocs.length + '*' }] });

const fallback = 'Company Knowledge Answer: ' + question;

return { blocks, fallback };
